1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	export function quote(input: { customer: { yearsInsured: number; previousContracts: number }; items: Array<{ type: string; cursed?: boolean; enchantment?: number }> }): { premium: number } {
16	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
17	
18	  const componentCounts: Record<string, number> = {};
19	  let base = 0;
20	  let itemSubtotal = 0;
21	  for (const item of input.items) {
22	    if (COMPONENT_TYPES.has(item.type)) {
23	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
24	    } else {
25	      const itemBase = BASE_PREMIUMS[item.type];
26	      base += itemBase;
27	      itemSubtotal += itemBase + (item.cursed ? 0.5 * itemBase : 0) + ((item.enchantment ?? 0) >= 5 ? 0.3 * itemBase : 0);
28	    }
29	  }
30	  for (const [type, count] of Object.entries(componentCounts)) {
31	    const componentBase = count === 3 ? 60 : count * BASE_PREMIUMS[type];
32	    base += componentBase;
33	    itemSubtotal += componentBase;
34	  }
35	
36	  const loyalty = input.customer.yearsInsured >= 2 ? -0.2 * base : 0;
37	  const followUp = input.customer.previousContracts >= 1 ? -0.15 * base : 0;
38	  return { premium: Math.ceil(itemSubtotal + base * FIRST_INSURANCE_RATE + loyalty + followUp + PROCESSING_FEE) };
39	}
40	
41	const INSURANCE_VALUES: Record<string, number> = {
42	  sword: 1000,
43	  amulet: 600,
44	  staff: 800,
45	  potion: 400,
46	  rune: 250,
47	  moonstone: 250,
48	};
49	
50	export function claim(input: { items: Array<{ type: string; material?: string; enchantment?: number }>; damages: Array<{ itemType: string; amount: number }> }): { payout: number; remainingCap: number } {
51	  const itemCounts: Record<string, number> = {};
52	  for (const item of input.items) {
53	    itemCounts[item.type] = (itemCounts[item.type] ?? 0) + 1;
54	  }
55	  const damageCounts: Record<string, number> = {};
56	  for (const damage of input.damages) {
57	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
58	  }
59	  for (const [type, count] of Object.entries(damageCounts)) {
60	    if (count > (itemCounts[type] ?? 0)) {
61	      throw new Error(`more ${type} damages than insured`);
62	    }
63	  }
64	  let payout = 0;
65	  for (const damage of input.damages) {
66	    const item = input.items.find((i) => i.type === damage.itemType);
67	    let amount = damage.amount;
68	    if (item && (item.enchantment ?? 0) >= 8) amount = amount * 0.5;
69	    payout += Math.max(0, amount - 100);
70	  }
71	  const insuranceSum = input.items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
72	  const cap = 2 * insuranceSum;
73	  const finalPayout = Math.floor(payout);
74	  return { payout: finalPayout, remainingCap: cap - finalPayout };
75	}
